from decimal import Decimal

@dataclass
class Transaction:
    tx_id: str
    amount: Decimal
    currency: str

    def __post_init__(self):
        if not isinstance(self.amount, Decimal):
            raise TypeError("amount must be Decimal")
        self.amount = self.amount.quantize(Decimal("0.01"))
        if self.amount <= 0:
            raise ValueError("amount must be > 0")
        if self.currency not in {"PEN", "USD"}:
            raise ValueError("currency not allowed")

print(Transaction("T1", Decimal("10.5"), "PEN"))
for args in [(Decimal("0"), "PEN"), (Decimal("1"), "EUR")]:
    try:
        Transaction("T2", *args)
    except ValueError as e:
        print("reject", e)

